  ('pukao-d0d1b9a2-moex-00324', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-fa8ff513', 'sub-pukao-d0d1b9a2-01', NULL, 'single_choice', '依行政院主計總處函頒之折舊及攤銷計算原則，丙機關110年7月16日購買一台冷氣機99,800 元，估計使用年限10年，殘值200元，於每月底提列折舊，110年7月底提列折舊之會計分錄為 何？', '["不做分錄", "借：固定資產折舊830，貸：累計折舊–機械及設備830", "借：固定資產折舊830，貸：機械及設備830", "借：固定資產折舊415，貸：累計折舊–機械及設備415"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "9b11d9085dde", "answer_pdf_sha1": "ec1d090c125d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
