  ('pukao-d0d1b9a2-moex-00326', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-fa8ff513', 'sub-pukao-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第4號之規定，甲機關購建固定資產，下列成本項目何者得資本化？①購建', '["施工成本", "監造成本", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:03+00:00", "source_pdf_sha1": "9b11d9085dde", "answer_pdf_sha1": "ec1d090c125d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
